import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/Dashboard.css';

function Dashboard({ jobs, onJobSelect }) {
  const [selectedJobId, setSelectedJobId] = useState('');
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [generating, setGenerating] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleJobChange = (e) => {
    setSelectedJobId(e.target.value);
    if (onJobSelect) onJobSelect(e.target.value);
  };

  const generateRankings = async () => {
    if (!selectedJobId) {
      setMessage({ type: 'error', text: 'Please select a job first' });
      return;
    }

    setGenerating(true);
    setMessage({ type: '', text: '' });

    try {
      const response = await axios.post(
        `http://localhost:5000/api/rankings/generate/${selectedJobId}`
      );

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Rankings generated successfully!' });
        fetchRankings();
      }
    } catch (error) {
      setMessage({ 
        type: 'error', 
        text: error.response?.data?.message || 'Error generating rankings' 
      });
    } finally {
      setGenerating(false);
    }
  };

  const fetchRankings = async () => {
    if (!selectedJobId) return;

    setLoading(true);
    try {
      const response = await axios.get(
        `http://localhost:5000/api/rankings/job/${selectedJobId}`
      );

      if (response.data.success) {
        setRankings(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching rankings:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (selectedJobId) {
      fetchRankings();
    }
  }, [selectedJobId]);

  const updateStatus = async (rankingId, newStatus) => {
    try {
      await axios.patch(
        `http://localhost:5000/api/rankings/${rankingId}/status`,
        { status: newStatus }
      );
      fetchRankings();
    } catch (error) {
      console.error('Error updating status:', error);
    }
  };

  const getScoreColor = (score) => {
    if (score >= 80) return '#10b981';
    if (score >= 60) return '#f59e0b';
    if (score >= 40) return '#f97316';
    return '#ef4444';
  };

  const exportResults = () => {
    const csvContent = [
      ['Rank', 'Candidate', 'Email', 'Match %', 'Score', 'Matched Skills', 'Missing Skills', 'Status'],
      ...rankings.map(r => [
        r.rank,
        r.resumeId?.candidateName || 'N/A',
        r.resumeId?.email || 'N/A',
        r.matchPercentage.toFixed(2),
        r.similarityScore.toFixed(2),
        r.matchedSkills.join('; '),
        r.missingSkills.join('; '),
        r.status
      ])
    ].map(row => row.join(',')).join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `rankings_${selectedJobId}_${Date.now()}.csv`;
    a.click();
  };

  return (
    <div className="dashboard-container">
      <h2>📊 Resume Rankings Dashboard</h2>

      {message.text && (
        <div className={`message ${message.type}`}>
          {message.text}
        </div>
      )}

      <div className="dashboard-controls">
        <div className="control-group">
          <label htmlFor="job-select">Select Job:</label>
          <select
            id="job-select"
            value={selectedJobId}
            onChange={handleJobChange}
          >
            <option value="">-- Select a Job --</option>
            {jobs.map(job => (
              <option key={job._id} value={job._id}>
                {job.title} - {job.company || 'Company'}
              </option>
            ))}
          </select>
        </div>

        <button 
          className="generate-btn"
          onClick={generateRankings}
          disabled={!selectedJobId || generating}
        >
          {generating ? '⏳ Generating...' : '🔄 Generate Rankings'}
        </button>

        {rankings.length > 0 && (
          <button className="export-btn" onClick={exportResults}>
            📥 Export Results
          </button>
        )}
      </div>

      {loading ? (
        <div className="loading">Loading rankings...</div>
      ) : rankings.length > 0 ? (
        <div className="rankings-container">
          <div className="rankings-header">
            <h3>Top {rankings.length} Candidates</h3>
            <p>Ranked by AI similarity score</p>
          </div>

          <div className="rankings-list">
            {rankings.map((ranking) => (
              <div key={ranking._id} className="ranking-card">
                <div className="ranking-header">
                  <div className="rank-badge">#{ranking.rank}</div>
                  <div className="candidate-info">
                    <h4>{ranking.resumeId?.candidateName || 'Unknown'}</h4>
                    <p>{ranking.resumeId?.email || 'No email'}</p>
                  </div>
                  <div 
                    className="match-score"
                    style={{ color: getScoreColor(ranking.matchPercentage) }}
                  >
                    {ranking.matchPercentage.toFixed(1)}%
                  </div>
                </div>

                <div className="ranking-details">
                  <div className="detail-row">
                    <span className="label">Similarity Score:</span>
                    <span className="value">{ranking.similarityScore.toFixed(2)}</span>
                  </div>

                  <div className="detail-row">
                    <span className="label">Experience:</span>
                    <span className="value">{ranking.resumeId?.experience || 0} years</span>
                  </div>

                  {ranking.matchedSkills.length > 0 && (
                    <div className="skills-section">
                      <span className="label">✅ Matched Skills:</span>
                      <div className="skills-tags">
                        {ranking.matchedSkills.map((skill, idx) => (
                          <span key={idx} className="skill-tag matched">{skill}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {ranking.missingSkills.length > 0 && (
                    <div className="skills-section">
                      <span className="label">❌ Missing Skills:</span>
                      <div className="skills-tags">
                        {ranking.missingSkills.map((skill, idx) => (
                          <span key={idx} className="skill-tag missing">{skill}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className="status-controls">
                    <span className="label">Status:</span>
                    <select
                      value={ranking.status}
                      onChange={(e) => updateStatus(ranking._id, e.target.value)}
                      className={`status-select ${ranking.status}`}
                    >
                      <option value="pending">Pending</option>
                      <option value="shortlisted">Shortlisted</option>
                      <option value="rejected">Rejected</option>
                    </select>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      ) : selectedJobId ? (
        <div className="empty-state">
          <p>No rankings available. Click "Generate Rankings" to analyze resumes.</p>
        </div>
      ) : (
        <div className="empty-state">
          <p>Please select a job to view rankings.</p>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
